SELECT * FROM ( SELECT ROWNUM AS RN, T.* FROM ( SELECT A.ANIMAL_ID AS animalId, A.ANIMAL_NAME AS animalName, A.ANIMAL_TYPE AS animalType, A.BREED AS breed, A.GENDER AS gender, A.AGE AS age, A.WEIGHT AS weight, A.ADOPTION_STATUS AS adoptionStatus, A.PERSONALITY AS personality, A.VIEW_COUNT AS viewCount, A.CREATE_DATE AS createDate, I.SAVE_FILE_NAME AS mainImage FROM ANIMAL A LEFT OUTER JOIN ANIMAL_IMAGE I ON A.ANIMAL_ID = I.ANIMAL_ID AND I.IS_MAIN = 'Y' WHERE 1=1
ORDER BY A.VIEW_COUNT DESC ORDER BY A.CREATE_DATE DESC
) T WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}

